function attachLogs(from, task) {
  return new Promise((resolve, reject) => {
    const { stdout, stderr } = require('child_process').spawnSync('docker', ['logs', from]);
    if (stdout) {
      resolve({
        logs: stdout.toString().trim(),
        error: null,
      });
    } else if (stderr) {
      resolve({
        logs: null,
        error: stderr.toString().trim(),
      });
    } else {
      reject(new Error(`No output from 'docker logs ${from}'`));
    }
  });
}
```

