std::string markdownToHTML(const std::string& markdown) {
    std::unordered_map<char, std::string> replacements = {
        {'*', '<strong>'}, {'[', '<a href="javascript:void(0)">'}, {']', '</a>'}, {':', '<sup>'}, {'_', '<sub>'}
    };

    for (const auto& replacement : replacements) {
        markdown = markdown.replace(markdown.find(replacement.first), 1, replacement.second);
    }

    std::string html = markdown;
    html = html.replace(html.find("##"), 3, "<h2>");
    html = html.replace(html.find("#"), 2, "<h1>");
    html = html.replace(html.find("`"), 1, "<code>");
    html = html.replace(html.find("*"), 1, "<em>");

    return html;
}
```

